INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (1, 'MN 51', 'the Buddha to layman Pessa, MN 51', '*“Human beings are shady, while beasts are obvious.”* - **the Buddha to layman Pessa, MN 51**', '“Human beings are shady, while beasts are obvious.”', 1, 51, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (2, 'MN 8', 'the Buddha, MN 8', '*“Others will have sex, but here we will not have sex.”* - **the Buddha, MN 8**', '“Others will have sex, but here we will not have sex.”', 1, 54, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (3, 'MN 26', 'the Buddha, MN 26', '*“What should be described as liable to corruption? Partners and children”* - **the Buddha, MN 26**', '“What should be described as liable to corruption? Partners and children”', 1, 73, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (4, 'MN 87', 'the Buddha to a householder, MN 87', '*“Our loved ones are a source of sorrow, lamentation, pain, sadness, and distress.”* - **the Buddha to a householder, MN 87**', '“Our loved ones are a source of sorrow, lamentation, pain, sadness, and distress.”', 1, 82, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (5, 'MN 22', 'the Buddha, MN 22', '*“In the past, as today, what I teach is just suffering and the cessation of suffering.”* - **the Buddha, MN 22**', '“In the past, as today, what I teach is just suffering and the cessation of suffering.”', 1, 87, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (6, 'SN 42.3', 'the Buddha, SN 42.3', '*“An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”* - **the Buddha, SN 42.3**', '“An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”', 1, 96, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (7, 'AN 3.318', 'the Buddha, AN 3.318', '*“Mendicants, I do not see a single thing that is so very blameworthy as wrong view. Wrong view is the most blameworthy thing of all.”* - **the Buddha, AN 3.318**', '“Mendicants, I do not see a single thing that is so very blameworthy as wrong view. Wrong view is the most blameworthy thing of all.”', 1, 133, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (8, 'MN 56', 'the Buddha, MN 56', '*“The doctrine of the foolish Jains looks fine initially: for fools, not for the astute, but can’t endure being scrutinized or pressed.”* - **the Buddha, MN 56**', '“The doctrine of the foolish Jains looks fine initially: for fools, not for the astute, but can’t endure being scrutinized or pressed.”', 1, 135, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (9, 'SN 22.43', 'the Buddha, SN 22.43', '*“Mendicants, be your own island, your own refuge, with no other refuge.*  
*Let the teaching be your island and your refuge, with no other refuge.”* - **the Buddha, SN 22.43**', '“Mendicants, be your own island, your own refuge, with no other refuge.
Let the teaching be your island and your refuge, with no other refuge.”', 2, 142, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (10, 'MN 117', 'the Buddha, MN 117', '*“And what, bhikkhus, is wrong intention? The intention of sensual desire, the intention of ill will, and the intention of cruelty: this is wrong intention.”* - **the Buddha, MN 117**', '“And what, bhikkhus, is wrong intention? The intention of sensual desire, the intention of ill will, and the intention of cruelty: this is wrong intention.”', 1, 156, 'sacredness-and-profanity.txt;stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (11, 'AN 3.107', 'the Buddha, AN 3.107', '*“Singing is regarded as wailing in the training of the Noble One. Dancing is regarded as madness. Too much laughter, showing the teeth, is regarded as childish.”* - **the Buddha, AN 3.107**', '“Singing is regarded as wailing in the training of the Noble One. Dancing is regarded as madness. Too much laughter, showing the teeth, is regarded as childish.”', 1, 161, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (12, 'MN 22', 'the Buddha, MN 22', '*“Bhikkhus, that one can engage in sexual pleasures without sexual desires, without perceptions of sexual desire, without thoughts of sexual desire: that is impossible.”* - **the Buddha, MN 22**', '“Bhikkhus, that one can engage in sexual pleasures without sexual desires, without perceptions of sexual desire, without thoughts of sexual desire: that is impossible.”', 1, 168, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (13, 'MN 22', 'the Buddha, MN 22', '*“Mendicants, that one can engage in sexual pleasures without sexual desires, without perceptions of sexual desire, without thoughts of sexual desire: that is impossible.”* - **the Buddha, MN 22**', '“Mendicants, that one can engage in sexual pleasures without sexual desires, without perceptions of sexual desire, without thoughts of sexual desire: that is impossible.”', 1, 170, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (14, 'MN 22', 'the Buddha, MN 22', '*“Bhikkhus, that one can engage in sensual pleasures without sensual desires, without perceptions of sensual desire, without thoughts of sensual desire: that is impossible.”* - **the Buddha, MN 22**', '“Bhikkhus, that one can engage in sensual pleasures without sensual desires, without perceptions of sensual desire, without thoughts of sensual desire: that is impossible.”', 1, 172, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (15, 'AN 1.328', 'the Buddha, AN 1.328', '*“Just as, mendicants, even a little bit of fecal matter still stinks, so too I don’t approve of even a little bit of continued existence, not even as long as a finger-snap.”* - **the Buddha, AN 1.328**', '“Just as, mendicants, even a little bit of fecal matter still stinks, so too I don’t approve of even a little bit of continued existence, not even as long as a finger-snap.”', 1, 173, 'sacredness-and-profanity.txt;stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (16, 'MN 21', 'the Buddha, MN 21', '*“Even if low-down bandits were to sever you limb from limb with a two-handed saw, anyone who had a malevolent thought on that account would not be following my instructions.”* - **the Buddha, MN 21**', '“Even if low-down bandits were to sever you limb from limb with a two-handed saw, anyone who had a malevolent thought on that account would not be following my instructions.”', 1, 174, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (17, 'KN Snp 2.14', 'the Buddha, KN Snp 2.14', '*“Let the intelligent person live a celibate life,*  
*as one would avoid a pit of glowing coals*  
*but being unable to live the celibate life,*  
*go not beyond the bounds with others’ partners.”* - **the Buddha, KN Snp 2.14**', '“Let the intelligent person live a celibate life,
as one would avoid a pit of glowing coals
but being unable to live the celibate life,
go not beyond the bounds with others’ partners.”', 4, 181, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (18, 'KN Iti 25', 'the Buddha, KN Iti 25', '*“Mendicants, for an individual person who transgresses in one thing, there is no atrocity that evil person would not do, I say. What one thing? It is this: telling a deliberate lie.”* - **the Buddha, KN Iti 25**', '“Mendicants, for an individual person who transgresses in one thing, there is no atrocity that evil person would not do, I say. What one thing? It is this: telling a deliberate lie.”', 1, 182, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (19, 'KN Snp 2.14', 'the Buddha to layman Dhammika, KN Snp 2.14', '*“Any intelligent person would avoid the non-celibate life, like a burning pit of glowing charcoals.*  
*But if too mentally weak to remain celibate, they’d at least not transgress with another’s wives.”* - **the Buddha to layman Dhammika, KN Snp 2.14**', '“Any intelligent person would avoid the non-celibate life, like a burning pit of glowing charcoals.
But if too mentally weak to remain celibate, they’d at least not transgress with another’s wives.”', 2, 197, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (20, 'AN 5.177', 'the Buddha, AN 5.177', '*“Mendicants, a lay follower should not engage in these five trades. What five? Trade in weapons, living beings, meat, intoxicants, and poisons. A lay follower should not engage in these five trades.”* - **the Buddha, AN 5.177**', '“Mendicants, a lay follower should not engage in these five trades. What five? Trade in weapons, living beings, meat, intoxicants, and poisons. A lay follower should not engage in these five trades.”', 1, 199, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (21, 'MN 51', 'the Buddha, MN 51', '*“They refrain from running errands and messages; buying and selling; falsifying weights, metals, or measures; bribery, fraud, cheating, and duplicity; mutilation, murder, abduction, banditry, plunder, and violence.”* - **the Buddha, MN 51**', '“They refrain from running errands and messages; buying and selling; falsifying weights, metals, or measures; bribery, fraud, cheating, and duplicity; mutilation, murder, abduction, banditry, plunder, and violence.”', 1, 215, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (22, 'AN 3.163', 'the Buddha, AN 3.163', '*“Someone with three qualities is placed in hell as if delivered there. What three? They themselves kill living creatures. They encourage others to kill living creatures. And they approve of killing living creatures.”* - **the Buddha, AN 3.163**', '“Someone with three qualities is placed in hell as if delivered there. What three? They themselves kill living creatures. They encourage others to kill living creatures. And they approve of killing living creatures.”', 1, 216, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (23, 'SN 5.2', 'the Buddha, SN 5.2', '*“What difference does womanhood make*  
*when the mind is serene,*  
*and knowledge is present*  
*as you rightly discern the Dhamma.*  
*Surely someone who might think:*  
*‘I am woman’, or ‘I am man’,*  
*or ‘I am’ anything at all,*  
*is fit for Māra to address.”* - **the Buddha, SN 5.2**', '“What difference does womanhood make
when the mind is serene,
and knowledge is present
as you rightly discern the Dhamma.
Surely someone who might think:
‘I am woman’, or ‘I am man’,
or ‘I am’ anything at all,
is fit for Māra to address.”', 8, 231, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (24, 'AN 1.320', 'the Buddha, AN 1.320', '*“Mendicants, the one who encourages someone in a poorly explained teaching and training, the one who they encourage, and the one who practices accordingly all brim with much evil. Why is that? Because the teaching is poorly explained.”* - **the Buddha, AN 1.320**', '“Mendicants, the one who encourages someone in a poorly explained teaching and training, the one who they encourage, and the one who practices accordingly all brim with much evil. Why is that? Because the teaching is poorly explained.”', 1, 235, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (25, 'AN 10.46', 'the Buddha, AN 10.46', '*“Sakyans, do you observe the sabbath with its eight precepts?”*  
*“Sir, sometimes we do, sometimes we don’t.”*  
*“That’s your loss, Sakyans, it’s your misfortune. In this life with its fear of sorrow and death, you sometimes keep the sabbath and you sometimes don’t.”* - **the Buddha, AN 10.46**', '“Sakyans, do you observe the sabbath with its eight precepts?”
“Sir, sometimes we do, sometimes we don’t.”
“That’s your loss, Sakyans, it’s your misfortune. In this life with its fear of sorrow and death, you sometimes keep the sabbath and you sometimes don’t.”', 3, 259, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (26, 'AN 3.31', 'the Buddha, AN 3.31', '*“‘Divinity’ is a term for your parents.*  
*‘First tutors’ is a term for your parents.*  
*‘Worthy of offerings dedicated to the gods’ is a term for your parents.*  
*Why is that? Parents are very helpful to their children, they raise them, nurture them, and show them the world.”* - **the Buddha, AN 3.31**', '“‘Divinity’ is a term for your parents.
‘First tutors’ is a term for your parents.
‘Worthy of offerings dedicated to the gods’ is a term for your parents.
Why is that? Parents are very helpful to their children, they raise them, nurture them, and show them the world.”', 4, 265, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (27, 'AN 4.77', 'the Buddha, AN 4.77', '*“Mendicants, these four things are unthinkable. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated. What four?*  
*The domain of the Buddhas …*  
*The domain of one in jhana …*  
*The results of deeds …*  
*Speculation about the world.”* - **the Buddha, AN 4.77**', '“Mendicants, these four things are unthinkable. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated. What four?
The domain of the Buddhas …
The domain of one in jhana …
The results of deeds …
Speculation about the world.”', 5, 270, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (28, 'DN 16', 'These were the Buddha’s, the Realized One’s last words, DN 16', '*“I’ve taught the Dhamma without making any distinction between secret and public teachings. The Realized One doesn’t have the closed fist of a tutor when it comes to the teachings. …*  
*Come now, mendicants, I say to you all: ‘Conditions fall apart. Persist with diligence.’”* - **These were the Buddha’s, the Realized One’s last words, DN 16**', '“I’ve taught the Dhamma without making any distinction between secret and public teachings. The Realized One doesn’t have the closed fist of a tutor when it comes to the teachings. …
Come now, mendicants, I say to you all: ‘Conditions fall apart. Persist with diligence.’”', 2, 271, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (29, 'SN 22.59', 'the Buddha, SN 22.59', '*“Is consciousness permanent or impermanent?”*  
*“Impermanent, sir.”*  
*“But if it’s impermanent, is it suffering or happiness?”*  
*“Suffering, sir.”*  
*“But if it’s impermanent, suffering, and perishable, is it fit to be regarded thus: ‘This is mine, I am this, this is my self’?”*  
*“No, sir.”* - **the Buddha, SN 22.59**', '“Is consciousness permanent or impermanent?”
“Impermanent, sir.”
“But if it’s impermanent, is it suffering or happiness?”
“Suffering, sir.”
“But if it’s impermanent, suffering, and perishable, is it fit to be regarded thus: ‘This is mine, I am this, this is my self’?”
“No, sir.”', 6, 274, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (30, 'AN 5.129', 'the Buddha, AN 5.129', '*“Mendicants, these five fatal wounds lead to a place of loss, to hell. What five? Murdering your mother or father or a perfected one; maliciously shedding the blood of a Realized One; and causing a schism in the Saṅgha. These five fatal wounds lead to a place of loss, to hell.”* - **the Buddha, AN 5.129**', '“Mendicants, these five fatal wounds lead to a place of loss, to hell. What five? Murdering your mother or father or a perfected one; maliciously shedding the blood of a Realized One; and causing a schism in the Saṅgha. These five fatal wounds lead to a place of loss, to hell.”', 1, 278, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (31, 'AN 1.278-286', 'the Buddha, AN 1.278-286', '*“It is impossible, mendicants, it cannot happen for a likable, desirable, agreeable result to come from bad bodily … bad verbal … bad mental conduct. But it is possible for an unlikable, undesirable, disagreeable result to come from bad bodily … bad verbal … bad mental conduct.”* - **the Buddha, AN 1.278-286**', '“It is impossible, mendicants, it cannot happen for a likable, desirable, agreeable result to come from bad bodily … bad verbal … bad mental conduct. But it is possible for an unlikable, undesirable, disagreeable result to come from bad bodily … bad verbal … bad mental conduct.”', 1, 279, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (32, 'AN 8.12', 'layman Siha, AN 8.12', '*“For a long time those venerables have wanted to discredit the Buddha, his teaching, and his Saṅgha. They’ll never stop misrepresenting the Buddha with their incorrect, hollow, false, untruthful claims. We would never deliberately take the life of a living creature, not even for life’s sake.”* - **layman Siha, AN 8.12**', '“For a long time those venerables have wanted to discredit the Buddha, his teaching, and his Saṅgha. They’ll never stop misrepresenting the Buddha with their incorrect, hollow, false, untruthful claims. We would never deliberately take the life of a living creature, not even for life’s sake.”', 1, 293, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (33, 'MN 82', 'the Buddha, MN 82', '*“‘The world is unstable and swept away.’ This is the first summary.*  
*‘The world has no shelter and no savior.’ This is the second summary.*  
*‘The world has no owner: you must leave it all behind and pass on.’ This is the third summary.*  
*‘The world is wanting, insatiable, the slave of craving.’ This is the fourth summary of the teaching.”* - **the Buddha, MN 82**', '“‘The world is unstable and swept away.’ This is the first summary.
‘The world has no shelter and no savior.’ This is the second summary.
‘The world has no owner: you must leave it all behind and pass on.’ This is the third summary.
‘The world is wanting, insatiable, the slave of craving.’ This is the fourth summary of the teaching.”', 4, 332, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (34, 'AN 4.159', 'the Buddha, AN 4.159', '*“Sister, this body is produced by food. Relying on food, you should give up food. This body is produced by craving. Relying on craving, you should give up craving. This body is produced by conceit. Relying on conceit, you should give up conceit. This body is produced by sex. The Buddha spoke of breaking off everything to do with sex.”* - **the Buddha, AN 4.159**', '“Sister, this body is produced by food. Relying on food, you should give up food. This body is produced by craving. Relying on craving, you should give up craving. This body is produced by conceit. Relying on conceit, you should give up conceit. This body is produced by sex. The Buddha spoke of breaking off everything to do with sex.”', 1, 336, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (35, 'AN 1.316', 'the Buddha, AN 1.316', '*“One individual, mendicants, arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans. What one individual? Someone with wrong view, whose perspective is distorted. They draw many people away from the true teaching and establish them in false teachings.”* - **the Buddha, AN 1.316**', '“One individual, mendicants, arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans. What one individual? Someone with wrong view, whose perspective is distorted. They draw many people away from the true teaching and establish them in false teachings.”', 1, 342, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (36, 'SN 45.24', 'the Buddha, SN 45.24', '*“Bhikkhus, whether for a layperson or one gone forth, I do not praise the wrong way. Whether it is a layperson or one gone forth who is practising wrongly, because of undertaking the wrong way of practice he does not attain the method, the Dhamma that is wholesome. And what, bhikkhus, is the wrong way? It is: wrong view, wrong intention, …”* - **the Buddha, SN 45.24**', '“Bhikkhus, whether for a layperson or one gone forth, I do not praise the wrong way. Whether it is a layperson or one gone forth who is practising wrongly, because of undertaking the wrong way of practice he does not attain the method, the Dhamma that is wholesome. And what, bhikkhus, is the wrong way? It is: wrong view, wrong intention, …”', 1, 342, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (37, 'AN 7.49', 'the Buddha, AN 7.49', '*“Mendicants, these seven perceptions, when developed and cultivated, are very fruitful and beneficial. They have freedom from death as their objective and culmination. What seven? The perceptions of ugliness, death, repulsiveness of food, dissatisfaction with the whole world, impermanence, suffering in impermanence, and not-self in suffering.”* - **the Buddha, AN 7.49**', '“Mendicants, these seven perceptions, when developed and cultivated, are very fruitful and beneficial. They have freedom from death as their objective and culmination. What seven? The perceptions of ugliness, death, repulsiveness of food, dissatisfaction with the whole world, impermanence, suffering in impermanence, and not-self in suffering.”', 1, 345, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (38, 'SN 45.24', 'the Buddha, SN 45.24', '*“Mendicants, whether for a layperson or one gone forth, I do not praise the wrong way. Whether it is a layperson or one gone forth who is practicing wrongly, because of undertaking the wrong way of practice he does not attain the method, the Dhamma that is wholesome. And what, mendicants, is the wrong way? It is: wrong view, wrong intention, …”* - **the Buddha, SN 45.24**', '“Mendicants, whether for a layperson or one gone forth, I do not praise the wrong way. Whether it is a layperson or one gone forth who is practicing wrongly, because of undertaking the wrong way of practice he does not attain the method, the Dhamma that is wholesome. And what, mendicants, is the wrong way? It is: wrong view, wrong intention, …”', 1, 346, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (39, 'SN 13.11', 'the Buddha, SN 13.11', '*“Sir, the great earth is far more. The little bit of dirt on your fingernail is tiny. Compared to the great earth, it’s not nearly a hundredth, a thousandth, or a hundred thousandth part.”*  
*“In the same way, for a noble disciple accomplished in view, an individual with comprehension, the suffering that’s over and done with is more, what’s left is tiny.”* - **the Buddha, SN 13.11**', '“Sir, the great earth is far more. The little bit of dirt on your fingernail is tiny. Compared to the great earth, it’s not nearly a hundredth, a thousandth, or a hundred thousandth part.”
“In the same way, for a noble disciple accomplished in view, an individual with comprehension, the suffering that’s over and done with is more, what’s left is tiny.”', 2, 353, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (40, 'KN Ud 8.8', 'the Buddha, KN Ud 8.8', '*“Those who have a hundred loved ones, Visākhā, have a hundred sufferings. Those who have ninety loved ones, or eighty, seventy, sixty, fifty, forty, thirty, twenty, ten, nine, eight, seven, six, five, four, three, two, or one loved one have one suffering. Those who have no loved ones have no suffering. They are free of sorrow, stains, and anguish I say.”* - **the Buddha, KN Ud 8.8**', '“Those who have a hundred loved ones, Visākhā, have a hundred sufferings. Those who have ninety loved ones, or eighty, seventy, sixty, fifty, forty, thirty, twenty, ten, nine, eight, seven, six, five, four, three, two, or one loved one have one suffering. Those who have no loved ones have no suffering. They are free of sorrow, stains, and anguish I say.”', 1, 356, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (41, 'AN 3.69', 'the Buddha, AN 3.69', '*“Mendicants, there are these three evil roots. What three? Greed, hate, and delusion.*  
*Greed … hate … delusion is a root of evil. When a greedy … hateful … delusional person chooses to act by way of body, speech, or mind, that person is evil. … And so these many evil, unskillful things are produced in them, born, sourced, originated, and conditioned by greed … hate … delusion“* - **the Buddha, AN 3.69**', '“Mendicants, there are these three evil roots. What three? Greed, hate, and delusion.
Greed … hate … delusion is a root of evil. When a greedy … hateful … delusional person chooses to act by way of body, speech, or mind, that person is evil. … And so these many evil, unskillful things are produced in them, born, sourced, originated, and conditioned by greed … hate … delusion“', 2, 377, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (42, 'AN 4.77', 'the Buddha, AN 4.77', '*“Mendicants, these four things are unthinkable. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated. What four?*  
*The domain of the Buddhas …*  
*The domain of one in jhana …*  
*The results of deeds …*  
*Speculation about the world …*  
*These are the four unthinkable things. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated.”* - **the Buddha, AN 4.77**', '“Mendicants, these four things are unthinkable. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated. What four?
The domain of the Buddhas …
The domain of one in jhana …
The results of deeds …
Speculation about the world …
These are the four unthinkable things. They should not be thought about, and anyone who tries to think about them will go mad or get frustrated.”', 6, 415, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (43, 'AN 8.53', 'the Buddha, AN 8.53', '*“Gotamī, you might know that certain things lead to passion, not dispassion; to yoking, not to unyoking; to accumulation, not dispersal; to more desires, not fewer; to lack of contentment, not contentment; to crowding, not seclusion; to laziness, not energy; to being burdensome, not being unburdensome. Categorically, you should remember these things as not the teaching, not the training, and not the Teacher’s instructions.”* - **the Buddha, AN 8.53**', '“Gotamī, you might know that certain things lead to passion, not dispassion; to yoking, not to unyoking; to accumulation, not dispersal; to more desires, not fewer; to lack of contentment, not contentment; to crowding, not seclusion; to laziness, not energy; to being burdensome, not being unburdensome. Categorically, you should remember these things as not the teaching, not the training, and not the Teacher’s instructions.”', 1, 427, 'sacredness-and-profanity.txt;stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (44, 'AN 5.180', 'the Buddha, AN 5.180', '*Then Gavesī thought: ‘I’m the helper, leader, and adviser of these five hundred lay followers, and both I and they have fulfilled the precepts. We’re the same, I’m in no way better. So let me do better.’*  
*Then Gavesī went to those five hundred lay followers and said to them: ‘From this day forth may the venerables remember me as one who is celibate, set apart, avoiding the vulgar act of sex.’ Then those five hundred lay followers did the same.* - **the Buddha, AN 5.180**', 'Then Gavesī thought: ‘I’m the helper, leader, and adviser of these five hundred lay followers, and both I and they have fulfilled the precepts. We’re the same, I’m in no way better. So let me do better.’
Then Gavesī went to those five hundred lay followers and said to them: ‘From this day forth may the venerables remember me as one who is celibate, set apart, avoiding the vulgar act of sex.’ Then those five hundred lay followers did the same.', 2, 445, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (45, 'AN 1.287-295', 'the Buddha, AN 1.287-295', '*“It is impossible, mendicants, it cannot happen that someone who has engaged in bad bodily … bad verbal … bad mental conduct, could for that reason alone, when their body breaks up, after death, be reborn in a good place, a heavenly realm. But it is possible that someone who has engaged in bad bodily … bad verbal … bad mental conduct could, for that reason alone, when their body breaks up, after death, be reborn in a place of loss, a bad place, the underworld, hell.”* - **the Buddha, AN 1.287-295**', '“It is impossible, mendicants, it cannot happen that someone who has engaged in bad bodily … bad verbal … bad mental conduct, could for that reason alone, when their body breaks up, after death, be reborn in a good place, a heavenly realm. But it is possible that someone who has engaged in bad bodily … bad verbal … bad mental conduct could, for that reason alone, when their body breaks up, after death, be reborn in a place of loss, a bad place, the underworld, hell.”', 1, 471, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (46, 'AN 4.192', 'the Buddha, AN 4.192', '*“You can get to know a person’s ethics by living with them. But only after a long time, not casually; only when attentive, not when inattentive; and only by the wise, not the witless.*  
*You can get to know a person’s purity by dealing with them. …*  
*You can get to know a person’s resilience in times of trouble. …*  
*You can get to know a person’s wisdom by discussion. But only after a long time, not casually; only when attentive, not when inattentive; and only by the wise, not the witless.”* - **the Buddha, AN 4.192**', '“You can get to know a person’s ethics by living with them. But only after a long time, not casually; only when attentive, not when inattentive; and only by the wise, not the witless.
You can get to know a person’s purity by dealing with them. …
You can get to know a person’s resilience in times of trouble. …
You can get to know a person’s wisdom by discussion. But only after a long time, not casually; only when attentive, not when inattentive; and only by the wise, not the witless.”', 4, 485, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (47, 'AN 7.7', 'the Buddha, AN 7.7', '*“He has a hundred thousand gold coins, not to mention the silver coins!”*  
*“Well, Ugga, that is wealth, I can’t deny it. But fire, water, rulers, thieves, and unloved heirs all take a share of that wealth. There are these seven kinds of wealth that they can’t take a share of. What seven? The wealth of faith, ethics, conscience, prudence, learning, generosity, and wisdom. There are these seven kinds of wealth that fire, water, rulers, thieves, and unloved heirs can’t take a share of.”* - **the Buddha, AN 7.7**', '“He has a hundred thousand gold coins, not to mention the silver coins!”
“Well, Ugga, that is wealth, I can’t deny it. But fire, water, rulers, thieves, and unloved heirs all take a share of that wealth. There are these seven kinds of wealth that they can’t take a share of. What seven? The wealth of faith, ethics, conscience, prudence, learning, generosity, and wisdom. There are these seven kinds of wealth that fire, water, rulers, thieves, and unloved heirs can’t take a share of.”', 2, 485, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (48, 'SN 42.2', 'the Buddha, SN 42.2', '*“When sentient beings are still not free of greed, and are still bound by greed, an actor in a stage or festival presents them with even more arousing things …*  
*But if you have such a view: ‘Suppose an actor entertains and amuses people on a stage or at a festival with mixed truth and lies. When their body breaks up, after death, they’re reborn in the company of laughing gods.’ This is your wrong view. An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”* - **the Buddha, SN 42.2**', '“When sentient beings are still not free of greed, and are still bound by greed, an actor in a stage or festival presents them with even more arousing things …
But if you have such a view: ‘Suppose an actor entertains and amuses people on a stage or at a festival with mixed truth and lies. When their body breaks up, after death, they’re reborn in the company of laughing gods.’ This is your wrong view. An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”', 2, 499, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (49, 'AN 1.317', 'the Buddha, AN 1.317', '*“One individual, mendicants, arises in the world for the welfare and happiness of the people, for the people, for the benefit, welfare, and happiness of gods and humans. What one individual? Someone with right view, whose perspective is undistorted. They draw many people away from false teachings and establish them in the true teaching. This is one individuals who arises in the world for the welfare and happiness of the people, for the people, for the benefit, welfare, and happiness of gods and humans.”* - **the Buddha, AN 1.317**', '“One individual, mendicants, arises in the world for the welfare and happiness of the people, for the people, for the benefit, welfare, and happiness of gods and humans. What one individual? Someone with right view, whose perspective is undistorted. They draw many people away from false teachings and establish them in the true teaching. This is one individuals who arises in the world for the welfare and happiness of the people, for the people, for the benefit, welfare, and happiness of gods and humans.”', 1, 508, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (50, 'AN 1.316', 'the Buddha, AN 1.316', '*“One individual, mendicants, arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans. What one individual? Someone with wrong view, whose perspective is distorted. They draw many people away from the true teaching and establish them in false teachings. This is one individual who arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans”* - **the Buddha, AN 1.316**', '“One individual, mendicants, arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans. What one individual? Someone with wrong view, whose perspective is distorted. They draw many people away from the true teaching and establish them in false teachings. This is one individual who arises in the world for the detriment and suffering of the people, against the people, for the harm, detriment, and suffering of gods and humans”', 1, 514, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (51, 'AN 7.50', 'the Buddha, AN 7.50', '*“An ascetic or brahmin who claims to be celibate while not mutually engage in sex with a female (of any species). However, they consent to being anointed, massaged, bathed, and rubbed by a female. They enjoy it and like it and find it rewarding. This is a break, taint, stain, or mar in celibacy. This is called one who lives the celibate life impurely, yoked by the yoke of sex. They’re not freed from rebirth, old age, death, sorrow, lamentation, pain, sadness, and distress. They’re not freed from suffering, I say.”* - **the Buddha, AN 7.50**', '“An ascetic or brahmin who claims to be celibate while not mutually engage in sex with a female (of any species). However, they consent to being anointed, massaged, bathed, and rubbed by a female. They enjoy it and like it and find it rewarding. This is a break, taint, stain, or mar in celibacy. This is called one who lives the celibate life impurely, yoked by the yoke of sex. They’re not freed from rebirth, old age, death, sorrow, lamentation, pain, sadness, and distress. They’re not freed from suffering, I say.”', 1, 519, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (52, 'SN 42.3', 'the Buddha, SN 42.3', '*“When a soldier strives and struggles in battle, their mind is already low, degraded, and misdirected as they think: ‘May these sentient beings be killed, slaughtered, slain, destroyed, or annihilated!’ …*  
*But if you have such a view: ‘Suppose a soldier, while striving and struggling in battle, is killed and finished off by his foes. When his body breaks up, after death, he’s reborn in the company of the gods of the fallen.’ This is your wrong view. An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”* - **the Buddha, SN 42.3**', '“When a soldier strives and struggles in battle, their mind is already low, degraded, and misdirected as they think: ‘May these sentient beings be killed, slaughtered, slain, destroyed, or annihilated!’ …
But if you have such a view: ‘Suppose a soldier, while striving and struggling in battle, is killed and finished off by his foes. When his body breaks up, after death, he’s reborn in the company of the gods of the fallen.’ This is your wrong view. An individual with wrong view is reborn in one of two places, I say: hell or the animal realm.”', 2, 547, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (53, 'AN 3.69', 'the Buddha, AN 3.69', '*“Mendicants, there are these three unskillful roots. What three? Greed, hate, and delusion. Greed is a root of the unskillful. When a greedy person chooses to act by way of body, speech, or mind, that too is unskillful. When a greedy person, overcome by greed, causes another to suffer under a false pretext: by execution or imprisonment or confiscation or condemnation or banishment, thinking ‘I’m powerful, I want power’, that too is unskillful. And so these many bad, unskillful things are produced in them, born, sourced, originated, and conditioned by greed.”* - **the Buddha, AN 3.69**', '“Mendicants, there are these three unskillful roots. What three? Greed, hate, and delusion. Greed is a root of the unskillful. When a greedy person chooses to act by way of body, speech, or mind, that too is unskillful. When a greedy person, overcome by greed, causes another to suffer under a false pretext: by execution or imprisonment or confiscation or condemnation or banishment, thinking ‘I’m powerful, I want power’, that too is unskillful. And so these many bad, unskillful things are produced in them, born, sourced, originated, and conditioned by greed.”', 1, 564, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (54, 'pli-tv-bu-vb-pj1#5.11.20', 'the Buddha, pli-tv-bu-vb-pj1#5.11.20', '*“It would be better for your penis to enter the mouth of a black snake than to enter a woman. It would be better for your penis to enter a blazing charcoal pit than to enter a woman. Why is that? For although it might cause death or death-like suffering, it would not cause you to be reborn in a bad destination. But this might. Foolish man, you’ve practiced what is contrary to the true Teaching, the common practice, the low practice, the coarse practice, that which ends with a wash, that which is done in private, that which is done wherever there are couples.”* - **the Buddha, pli-tv-bu-vb-pj1#5.11.20**', '“It would be better for your penis to enter the mouth of a black snake than to enter a woman. It would be better for your penis to enter a blazing charcoal pit than to enter a woman. Why is that? For although it might cause death or death-like suffering, it would not cause you to be reborn in a bad destination. But this might. Foolish man, you’ve practiced what is contrary to the true Teaching, the common practice, the low practice, the coarse practice, that which ends with a wash, that which is done in private, that which is done wherever there are couples.”', 1, 565, 'sacredness-and-profanity.txt;stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (55, 'AN 10.176', 'the Buddha, AN 10.176', '*“… These are the ten ways of doing evil deeds. When you have these ten ways of doing evil deeds, then if you rise early, whether or not you stroke the earth from your bed … stroke fresh cow dung … stroke green grass … serve the sacred flame … revere the sun with cupped palms … immerse yourself in water three times (any ritual or prayer or vow), you’re still impure. Why is that? These ten ways of doing evil deeds are impure and make things impure.*  
*It’s because of those who do these ten kinds of evil deeds that hell, the animal realm, the ghost realm, or any other evil places are found.”* - **the Buddha, AN 10.176**', '“… These are the ten ways of doing evil deeds. When you have these ten ways of doing evil deeds, then if you rise early, whether or not you stroke the earth from your bed … stroke fresh cow dung … stroke green grass … serve the sacred flame … revere the sun with cupped palms … immerse yourself in water three times (any ritual or prayer or vow), you’re still impure. Why is that? These ten ways of doing evil deeds are impure and make things impure.
It’s because of those who do these ten kinds of evil deeds that hell, the animal realm, the ghost realm, or any other evil places are found.”', 2, 591, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (56, 'KN Snp 3.12', 'the Buddha, KN Snp 3.12', '*“‘All the suffering that originates is caused by consciousness’: this is one contemplation. ‘When consciousness has faded away and ceased with no residue left behind, there is no origination of suffering’: this is the second contemplation. When a mendicant meditates in this way they can expect enlightenment or non-return.” Then the Teacher went on to say:*  
*“All the suffering that originates is caused by consciousness. With the cessation of consciousness, there is no origination of suffering.*  
*Knowing this danger, that suffering is caused by consciousness, with the stilling of consciousness a mendicant is hungerless, quenched.”* - **the Buddha, KN Snp 3.12**', '“‘All the suffering that originates is caused by consciousness’: this is one contemplation. ‘When consciousness has faded away and ceased with no residue left behind, there is no origination of suffering’: this is the second contemplation. When a mendicant meditates in this way they can expect enlightenment or non-return.” Then the Teacher went on to say:
“All the suffering that originates is caused by consciousness. With the cessation of consciousness, there is no origination of suffering.
Knowing this danger, that suffering is caused by consciousness, with the stilling of consciousness a mendicant is hungerless, quenched.”', 3, 630, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (57, 'MN 38', 'the Buddha, MN 38', '*“Absolutely, sir. As I understand the Buddha’s teaching, it is this very same consciousness that roams and transmigrates, not another.”*  
*“Sāti, what is that consciousness?”*  
*“Sir, he is the one who speaks, the one who knows, who experiences the results of good and bad deeds in all the different realms.”*  
*“Futile man, who on earth have you ever known me to teach in that way? Haven’t I said in many ways that consciousness is dependently originated, since consciousness does not arise without a cause? But still you misrepresent me by your wrong grasp, harm yourself, and brim with much wickedness. This will be for your lasting harm and suffering.”* - **the Buddha, MN 38**', '“Absolutely, sir. As I understand the Buddha’s teaching, it is this very same consciousness that roams and transmigrates, not another.”
“Sāti, what is that consciousness?”
“Sir, he is the one who speaks, the one who knows, who experiences the results of good and bad deeds in all the different realms.”
“Futile man, who on earth have you ever known me to teach in that way? Haven’t I said in many ways that consciousness is dependently originated, since consciousness does not arise without a cause? But still you misrepresent me by your wrong grasp, harm yourself, and brim with much wickedness. This will be for your lasting harm and suffering.”', 4, 644, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (58, 'AN 9.7', 'the Buddha, AN 9.7', '*“In the past, as today, I say this: ‘A mendicant who is perfected, with defilements ended, who has completed the celibate life, done what had to be done, laid down the burden, achieved their heart’s goal, utterly ended the fetter of continued existence, and is rightly freed through enlightenment, can’t transgress in nine respects. A mendicant with defilements ended*  
*can’t deliberately take the life of a living creature,*  
*take something with the intention to steal,*  
*have sex,*  
*tell a deliberate lie,*  
*or store up goods for their own enjoyment like they did as a layperson.*  
*And they can’t make decisions prejudiced by favoritism,*  
*hostility,*  
*stupidity,*  
*or cowardice.’”* - **the Buddha, AN 9.7**', '“In the past, as today, I say this: ‘A mendicant who is perfected, with defilements ended, who has completed the celibate life, done what had to be done, laid down the burden, achieved their heart’s goal, utterly ended the fetter of continued existence, and is rightly freed through enlightenment, can’t transgress in nine respects. A mendicant with defilements ended
can’t deliberately take the life of a living creature,
take something with the intention to steal,
have sex,
tell a deliberate lie,
or store up goods for their own enjoyment like they did as a layperson.
And they can’t make decisions prejudiced by favoritism,
hostility,
stupidity,
or cowardice.’”', 10, 656, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (59, 'SN 8.4', 'the Buddha, SN 8.4', '*“I’ve got a burning desire for pleasure; My mind is on fire! Please, out of compassion, Gotama, tell me how to quench the flames.”*  
*“Your mind is on fire because of a perversion of perception. Turn away from the feature of things that’s attractive, provoking lust.*  
*See all conditioned phenomena as alien, as suffering and not-self. Extinguish the great fire of lust, don’t burn up again and again.*  
*With mind unified and serene, meditate on the ugly aspects of the body. With mindfulness immersed in the body, be full of disillusionment.*  
*Meditate on the signless, give up the underlying tendency to conceit; and when you comprehend conceit, you will live at peace.”* - **the Buddha, SN 8.4**', '“I’ve got a burning desire for pleasure; My mind is on fire! Please, out of compassion, Gotama, tell me how to quench the flames.”
“Your mind is on fire because of a perversion of perception. Turn away from the feature of things that’s attractive, provoking lust.
See all conditioned phenomena as alien, as suffering and not-self. Extinguish the great fire of lust, don’t burn up again and again.
With mind unified and serene, meditate on the ugly aspects of the body. With mindfulness immersed in the body, be full of disillusionment.
Meditate on the signless, give up the underlying tendency to conceit; and when you comprehend conceit, you will live at peace.”', 5, 659, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (60, 'AN 9.7', 'the Buddha, AN 9.7', '*“In the past, as today, I say this: ‘A mendicant who is perfected: with defilements ended, who has completed the spiritual journey, done what had to be done, laid down the burden, achieved their heart’s goal, utterly ended the fetter of continued existence, and is rightly freed through enlightenment, can’t transgress in nine respects. A mendicant with defilements ended*  
*can’t deliberately take the life of a living creature,*  
*take something with the intention to steal,*  
*have sex,*  
*tell a deliberate lie, or*  
*store up goods for their own enjoyment like they did as a layperson.*  
*And they can’t make decisions prejudiced by favoritism,*  
*hostility,*  
*stupidity, or*  
*cowardice.’”* - **the Buddha, AN 9.7**', '“In the past, as today, I say this: ‘A mendicant who is perfected: with defilements ended, who has completed the spiritual journey, done what had to be done, laid down the burden, achieved their heart’s goal, utterly ended the fetter of continued existence, and is rightly freed through enlightenment, can’t transgress in nine respects. A mendicant with defilements ended
can’t deliberately take the life of a living creature,
take something with the intention to steal,
have sex,
tell a deliberate lie, or
store up goods for their own enjoyment like they did as a layperson.
And they can’t make decisions prejudiced by favoritism,
hostility,
stupidity, or
cowardice.’”', 10, 660, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (61, 'KN Ud 5.5', 'the Buddha, KN Ud 5.5', '*“The ocean is consistent and doesn’t overflow its boundaries. In the same way, when a training rule is laid down for my disciples they wouldn’t break it even for the sake of their own life. This is the second thing the mendicants love about this teaching and training.*  
*The ocean doesn’t accommodate a carcass, but quickly carries it to the shore and strands it on the beach. In the same way, the Saṅgha doesn’t accommodate an individual who is immoral, of evil qualities, filthy, with suspicious behavior, underhand, no true ascetic or celibate practitioner: though claiming to be one, rotten inside, festering, and depraved. But they quickly gather and expel them.* - **the Buddha, KN Ud 5.5**', '“The ocean is consistent and doesn’t overflow its boundaries. In the same way, when a training rule is laid down for my disciples they wouldn’t break it even for the sake of their own life. This is the second thing the mendicants love about this teaching and training.
The ocean doesn’t accommodate a carcass, but quickly carries it to the shore and strands it on the beach. In the same way, the Saṅgha doesn’t accommodate an individual who is immoral, of evil qualities, filthy, with suspicious behavior, underhand, no true ascetic or celibate practitioner: though claiming to be one, rotten inside, festering, and depraved. But they quickly gather and expel them.', 2, 664, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (62, 'SN 16.13', 'the Buddha, SN 16.13', '*“It’s like native gold, which doesn’t disappear as long as counterfeit gold hasn’t appeared in the world. But when counterfeit gold appears in the world then native gold disappears.*  
*In the same way, the true teaching doesn’t disappear as long the counterfeit of the true teaching hasn’t appeared in the world. But when the counterfeit of the true teaching appears in the world then the true teaching disappears.*  
*It’s not the elements of earth, water, fire, or air that make the true teaching disappear. Rather, it’s the futile people who appear right here that make the true teaching disappear. The true teaching doesn’t disappear like a ship that sinks all at once.”* - **the Buddha, SN 16.13**', '“It’s like native gold, which doesn’t disappear as long as counterfeit gold hasn’t appeared in the world. But when counterfeit gold appears in the world then native gold disappears.
In the same way, the true teaching doesn’t disappear as long the counterfeit of the true teaching hasn’t appeared in the world. But when the counterfeit of the true teaching appears in the world then the true teaching disappears.
It’s not the elements of earth, water, fire, or air that make the true teaching disappear. Rather, it’s the futile people who appear right here that make the true teaching disappear. The true teaching doesn’t disappear like a ship that sinks all at once.”', 3, 665, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (63, 'SN 55.5', 'the Buddha, SN 55.5', '*“Sāriputta, … What is a factor for stream-entry?”*  
*“Sir, the factors for stream-entry are associating with true persons, listening to the true teaching, rational application of mind, and practicing in line with the teaching.”*  
*“Good, good, Sāriputta! …*  
*Sāriputta, … What is the stream?”*  
*“Sir, the stream is simply this noble eightfold path, that is: right view, right thought, right speech, right action, right livelihood, right effort, right mindfulness, and right immersion.”*  
*“Good, good, Sāriputta! …*  
*Sāriputta, they speak of ‘a stream-enterer’. What is a stream-enterer?”*  
*“Sir, anyone who possesses this noble eightfold path is called a stream-enterer …”*  
*“Good, good, Sāriputta! …”* - **the Buddha, SN 55.5**', '“Sāriputta, … What is a factor for stream-entry?”
“Sir, the factors for stream-entry are associating with true persons, listening to the true teaching, rational application of mind, and practicing in line with the teaching.”
“Good, good, Sāriputta! …
Sāriputta, … What is the stream?”
“Sir, the stream is simply this noble eightfold path, that is: right view, right thought, right speech, right action, right livelihood, right effort, right mindfulness, and right immersion.”
“Good, good, Sāriputta! …
Sāriputta, they speak of ‘a stream-enterer’. What is a stream-enterer?”
“Sir, anyone who possesses this noble eightfold path is called a stream-enterer …”
“Good, good, Sāriputta! …”', 9, 675, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (64, 'AN 4.180', 'the Buddha, AN 4.180', '*“Take a mendicant who says: ‘Reverend, I have heard and learned this in the presence of the Buddha: this is the teaching, this is the training, this is the Teacher’s instruction.’ You should neither approve nor reject that mendicant’s statement. Instead, having carefully memorized those words and phrases, you should make sure they fit in the discourse and are exhibited in the training. If they do not fit in the discourse and are not exhibited in the training, you should draw the conclusion: ‘Clearly this is not the word of the Blessed One, the perfected one, the fully awakened Buddha. It has been incorrectly memorized by that mendicant.’ And so you should discard it.”* - **the Buddha, AN 4.180**', '“Take a mendicant who says: ‘Reverend, I have heard and learned this in the presence of the Buddha: this is the teaching, this is the training, this is the Teacher’s instruction.’ You should neither approve nor reject that mendicant’s statement. Instead, having carefully memorized those words and phrases, you should make sure they fit in the discourse and are exhibited in the training. If they do not fit in the discourse and are not exhibited in the training, you should draw the conclusion: ‘Clearly this is not the word of the Blessed One, the perfected one, the fully awakened Buddha. It has been incorrectly memorized by that mendicant.’ And so you should discard it.”', 1, 676, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (65, 'MN 129', 'the Buddha, MN 129', '*“These are the three characteristics, signs, and manifestations of a moron. What three? A moron thinks stupidly, speaks foolishly, and acts moronic. If a moron didn’t think stupidly, speak foolishly, and act moronic, then how would the wise know of them, ‘This worthy one is a moron, a fake person’? But since a moron does think stupidly, speak foolishly, and act moronic, then the wise do know of them, ‘This worthy one is a moron, a fake person’.*  
*A moron experiences three kinds of suffering and sadness in this very life. …*  
*Having done evil things by way of body, speech, and mind, when their body breaks up, after death, they’re reappear in a place of loss, an evil place, the underworld, hell.”* - **the Buddha, MN 129**', '“These are the three characteristics, signs, and manifestations of a moron. What three? A moron thinks stupidly, speaks foolishly, and acts moronic. If a moron didn’t think stupidly, speak foolishly, and act moronic, then how would the wise know of them, ‘This worthy one is a moron, a fake person’? But since a moron does think stupidly, speak foolishly, and act moronic, then the wise do know of them, ‘This worthy one is a moron, a fake person’.
A moron experiences three kinds of suffering and sadness in this very life. …
Having done evil things by way of body, speech, and mind, when their body breaks up, after death, they’re reappear in a place of loss, an evil place, the underworld, hell.”', 3, 697, 'stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (66, 'SN 20.7', 'the Buddha, SN 20.7', '*“In a future time there will be mendicants who won’t want to listen when discourses spoken by the Realized One: deep, profound, transcendent, dealing with emptiness, are being recited. They won’t actively listen or try to understand, nor will they think those teachings are worth learning and memorizing.*  
*But when discourses composed by poets: poetry, with fancy words and phrases, composed by outsiders or spoken by disciples, are being recited they will want to listen. They’ll actively listen and try to understand, and they’ll think those teachings are worth learning and memorizing. And that is how the discourses spoken by the Realized One: deep, profound, transcendent, dealing with emptiness, will disappear.”* - **the Buddha, SN 20.7**', '“In a future time there will be mendicants who won’t want to listen when discourses spoken by the Realized One: deep, profound, transcendent, dealing with emptiness, are being recited. They won’t actively listen or try to understand, nor will they think those teachings are worth learning and memorizing.
But when discourses composed by poets: poetry, with fancy words and phrases, composed by outsiders or spoken by disciples, are being recited they will want to listen. They’ll actively listen and try to understand, and they’ll think those teachings are worth learning and memorizing. And that is how the discourses spoken by the Realized One: deep, profound, transcendent, dealing with emptiness, will disappear.”', 2, 716, 'sacredness-and-profanity.txt;stream-entry-for-lay-buddhists.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (67, 'AN 8.10', 'the Buddha, AN 8.10', '*“By living together, know that they’re irritable, with corrupt wishes, offensive, stubborn, and contemptuous, jealous, stingy, and devious.*  
*They speak to people with a voice so smooth, just like an ascetic. But they act in secret, with their bad views and their lack of regard for others.*  
*You should recognize them for what they are: a creep and liar. Then having gathered in harmony, you should expel them.*  
*Throw out the trash! Get rid of the rubbish! And sweep away the scraps: they’re not ascetics, they just think they are.*  
*When you’ve thrown out those of corrupt wishes, of bad behavior and alms-resort, dwell in communion, ever mindful, the pure with the pure. Then in harmony, alert, you’ll make an end of suffering.”* - **the Buddha, AN 8.10**', '“By living together, know that they’re irritable, with corrupt wishes, offensive, stubborn, and contemptuous, jealous, stingy, and devious.
They speak to people with a voice so smooth, just like an ascetic. But they act in secret, with their bad views and their lack of regard for others.
You should recognize them for what they are: a creep and liar. Then having gathered in harmony, you should expel them.
Throw out the trash! Get rid of the rubbish! And sweep away the scraps: they’re not ascetics, they just think they are.
When you’ve thrown out those of corrupt wishes, of bad behavior and alms-resort, dwell in communion, ever mindful, the pure with the pure. Then in harmony, alert, you’ll make an end of suffering.”', 5, 720, 'sacredness-and-profanity.txt');
INSERT INTO quotes (id, sutta_id, citation, body_md, body_text, line_count, char_count, sources) VALUES (68, 'AN 8.10', 'the Buddha, AN 8.10', '*“By living together, know that they’re irritable, with corrupt wishes, offensive, stubborn, and contemptuous, jealous, stingy, and devious.*  
*They speak to people with a voice so smooth, just like an ascetic. But they act in secret, with their evil views and their lack of regard for others.*  
*You should recognize them for what they are: a creep and liar. Then having gathered in harmony, you should expel them.*  
*Throw out the trash! Get rid of the rubbish! And sweep away the scraps: they’re not ascetics, they just think they are.*  
*When you’ve thrown out those of corrupt wishes, of bad behavior and alms-resort, dwell in communion, ever mindful, the pure with the pure. Then in harmony, alert, you’ll make an end of suffering.* - **the Buddha, AN 8.10**', '“By living together, know that they’re irritable, with corrupt wishes, offensive, stubborn, and contemptuous, jealous, stingy, and devious.
They speak to people with a voice so smooth, just like an ascetic. But they act in secret, with their evil views and their lack of regard for others.
